package com.restaurant.controller; import com.restaurant.common.ApiResponse; import com.restaurant.dto.coupon.*; import com.restaurant.service.CouponService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/admin/coupons") @RequiredArgsConstructor public class AdminCouponController { private final CouponService service; @GetMapping public ApiResponse<List<CouponResponse>> list(){return ApiResponse.ok("Coupons", service.list());} @PostMapping public ApiResponse<CouponResponse> create(@Valid @RequestBody CouponRequest r){return ApiResponse.ok("Coupon created", service.create(r));} @PatchMapping("/{id}/status") public ApiResponse<CouponResponse> status(@PathVariable Long id,@RequestBody Map<String,String> body){return ApiResponse.ok("Coupon status updated", service.status(id, body.get("status")));}}
